const d = $('Get Digest Date').first().json.digestDate;
const groqResp = $input.item.json;
const label = 'Support';
const addr = 'support@syntharra.com';
const SB_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SB_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImhnaGV5cXducmN2d3RnbmdxZG5xIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NDI5NTM1MiwiZXhwIjoyMDg5ODcxMzUyfQ.PENNZ2K5syVFyU3Yn6FfYZP1JEtmanlV6nTrlGaeqsg';

let classified = [];
try {
  const content = groqResp && groqResp.choices && groqResp.choices[0] ? groqResp.choices[0].message.content : '';
  classified = JSON.parse(typeof content === 'string' ? content : '{}').emails || [];
} catch(e) {
  return [{ json: { saved: 0, error: e.message, label: label, digestDate: d } }];
}

if (!classified.length) {
  return [{ json: { saved: 0, label: label, digestDate: d } }];
}

await this.helpers.httpRequest({
  method: 'DELETE',
  url: SB_URL + '/rest/v1/email_digest?digest_date=eq.' + d + '&inbox_address=eq.' + encodeURIComponent(addr),
  headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY }
});

const records = classified
  .filter(function(e) { return e && e.id && (e.importance === 'high' || e.importance === 'medium'); })
  .map(function(e) {
    let rx = null;
    try { rx = e.date ? new Date(e.date).toISOString() : null; } catch(_) {}
    return {
      digest_date: d, inbox_address: addr, inbox_label: label,
      email_id: String(e.id), thread_id: e.threadId || null,
      from_address: (e.from || '').substring(0,500),
      subject: (e.subject || '(no subject)').substring(0,500),
      snippet: (e.snippet || '').substring(0,500),
      ai_summary: (e.summary || '').substring(0,500),
      importance: e.importance, category: e.category || 'general',
      action_required: !!e.action_required,
      flag: (['urgent','opportunity','hire'].indexOf(e.flag) > -1) ? e.flag : null,
      received_at: rx
    };
  });

if (!records.length) {
  return [{ json: { saved: 0, label: label, digestDate: d } }];
}

await this.helpers.httpRequest({
  method: 'POST',
  url: SB_URL + '/rest/v1/email_digest',
  headers: {
    apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY,
    'Content-Type': 'application/json', Prefer: 'return=minimal'
  },
  body: JSON.stringify(records)
});

return [{ json: { saved: records.length, label: label, digestDate: d } }];

